proof fn phi_1_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_2_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    execution_equality::<int>(ex, ex.suffix(0));
}

proof fn phi_3_suffix_composition_equals_addition(ex: Execution<int>, i: nat, j: nat)
    ensures
        ex.suffix(i).suffix(j) == ex.suffix(i + j),
{
    execution_equality::<int>(ex.suffix(i).suffix(j), ex.suffix(i + j));
}

proof fn phi_4_rec_induction_missing_step_check(ex: Execution<int>, next: TempPred<int>, p: TempPred<int>, q: TempPred<int>, i: nat)
    requires
        forall |idx| p.satisfied_by(ex.suffix(idx)) && next.satisfied_by(ex.suffix(idx)) ==> p.satisfied_by(ex.suffix(idx + 1)) || q.satisfied_by(ex.suffix(idx + 1)),
        forall |idx| next.satisfied_by(#[trigger] ex.suffix(idx)),
        forall |idx| !q.satisfied_by(#[trigger] ex.suffix(idx)),
        p.satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)) && p.satisfied_by(ex.suffix(i + 1)),
{
    always_p_or_eventually_q_rec::<int>(ex, next, p, q, i);
    always_p_or_eventually_q_rec::<int>(ex, next, p, q, i + 1);
}

proof fn phi_5_rec_base_case_depends_on_execution_equality(ex: Execution<int>, p: TempPred<int>)
    requires
        p.satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(0)),
{
    execution_equality::<int>(ex, ex.suffix(0));
}
